INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'st-petersburg'), 'DC-1', 'dc-1', 'Downtown Center-1', 'Promotes redevelopment and a vibrant community center. Allows a variety of nonresidential uses complemented by residential uses at urban densities, supporting a pedestrian-oriented environment. Intended for both multiple-family residential and commercial uses, including small-scale office and service uses compatible with medium to medium-high density residential.', 55, NULL, NULL, NULL, 4, NULL, 12, 'Parking minimums for residential units in the downtown core with 750 sq ft or less were eliminated (specifics in Use Permissions and Parking Requirements Matrix).') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
